import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function AdminLogin() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [focusedInput, setFocusedInput] = useState(null);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form.email, form.password, true);
      toast.success('Admin access granted');
      navigate('/admin');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Invalid admin credentials');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      backgroundImage: `url('https://images.unsplash.com/photo-1550751827-4bd582f23d5c?w=2000&q=80')`,
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      backgroundAttachment: 'fixed',
      position: 'relative',
      overflow: 'hidden',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
    }}>

      {/* Premium Multi-Layer Overlay */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: `
          linear-gradient(135deg, 
            rgba(10, 13, 26, 0.88) 0%, 
            rgba(10, 18, 35, 0.86) 25%,
            rgba(8, 25, 45, 0.87) 50%,
            rgba(10, 13, 26, 0.88) 75%,
            rgba(10, 13, 26, 0.89) 100%
          ),
          radial-gradient(circle at 25% 40%, rgba(0, 212, 170, 0.10) 0%, transparent 50%),
          radial-gradient(circle at 75% 70%, rgba(6, 182, 212, 0.08) 0%, transparent 50%)
        `,
        pointerEvents: 'none',
        zIndex: 0,
      }} />

      {/* Animated Glow Orbs */}
      <div style={{
        position: 'fixed',
        top: '-30%',
        left: '-10%',
        width: '600px',
        height: '600px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(0, 212, 170, 0.15) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 0,
        filter: 'blur(80px)',
        animation: 'float 28s ease-in-out infinite',
      }} />
      <div style={{
        position: 'fixed',
        bottom: '-20%',
        right: '-10%',
        width: '700px',
        height: '700px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(6, 182, 212, 0.12) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 0,
        filter: 'blur(90px)',
        animation: 'float 32s ease-in-out infinite reverse',
      }} />

      {/* Subtle Grid Overlay */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: `linear-gradient(rgba(0, 212, 170, 0.015) 1px, transparent 1px), linear-gradient(90deg, rgba(0, 212, 170, 0.015) 1px, transparent 1px)`,
        backgroundSize: '60px 60px',
        pointerEvents: 'none',
        zIndex: 0,
        opacity: 0.4,
      }} />

      <style>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(50px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(50px); }
        }

        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.7; }
        }

        @keyframes glow {
          0%, 100% { box-shadow: 0 0 25px rgba(0, 212, 170, 0.15); }
          50% { box-shadow: 0 0 40px rgba(0, 212, 170, 0.25); }
        }

        @keyframes shimmer {
          0% {
            background-position: -1000px 0;
          }
          100% {
            background-position: 1000px 0;
          }
        }

        @keyframes inputFocus {
          0% {
            box-shadow: 0 0 0 rgba(0, 212, 170, 0);
          }
          100% {
            box-shadow: 0 0 30px rgba(0, 212, 170, 0.3);
          }
        }
      `}</style>

      {/* Main Content */}
      <div className="px-4 relative z-10">
        <div style={{
          width: '100%',
          maxWidth: 480,
          background: `linear-gradient(135deg, rgba(20, 35, 50, 0.96) 0%, rgba(15, 30, 45, 0.85) 100%)`,
          border: '1.5px solid rgba(0, 212, 170, 0.25)',
          backdropFilter: 'blur(30px)',
          animation: 'slideUp 0.8s ease-out',
          boxShadow: '0 50px 100px rgba(0, 212, 170, 0.15), inset 0 0 60px rgba(0, 212, 170, 0.08)'
        }}
        className="p-10 rounded-3xl relative overflow-hidden group">

          {/* Decorative Gradient Border */}
          <div style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            height: '2px',
            background: 'linear-gradient(90deg, rgba(0, 212, 170, 0.5) 0%, transparent 100%)',
          }} />

          {/* Header Section */}
          <div className="text-center mb-10" style={{ animation: 'slideUp 0.8s ease-out 0.1s both' }}>
            <div style={{
              fontSize: '48px',
              marginBottom: '16px',
              filter: 'drop-shadow(0 0 20px rgba(0, 212, 170, 0.6))',
            }}>⚙</div>
            <h1 style={{
              fontFamily: 'Syne, sans-serif',
              background: 'linear-gradient(135deg, #ffffff 0%, #00d4aa 100%)',
              backgroundClip: 'text',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              fontSize: '2.5rem',
              fontWeight: 900,
              letterSpacing: '-0.02em',
              marginBottom: '8px',
            }}>Admin Access</h1>
            <p style={{ color: '#a0aec0' }} className="text-sm font-medium">Restricted to authorized personnel only</p>
            <div style={{
              height: '2px',
              background: 'linear-gradient(90deg, transparent, rgba(0, 212, 170, 0.3), transparent)',
              marginTop: '16px',
            }} />
          </div>

          {/* Form Container */}
          <form onSubmit={handleSubmit} className="space-y-6" style={{ animation: 'slideUp 0.8s ease-out 0.2s both' }}>

            {/* Email Field */}
            <div>
              <label style={{ color: '#a0aec0' }} className="block text-sm font-bold mb-2.5 uppercase tracking-wider">
                Admin Email
              </label>
              <div style={{
                position: 'relative',
                display: 'flex',
                alignItems: 'center',
                background: 'linear-gradient(135deg, rgba(10, 13, 26, 0.96) 0%, rgba(10, 18, 35, 0.90) 100%)',
                border: `1.5px solid ${focusedInput === 'email' ? 'rgba(0, 212, 170, 0.5)' : 'rgba(0, 212, 170, 0.25)'}`,
                borderRadius: '14px',
                padding: '0 16px',
                transition: 'all 0.3s ease-out',
                boxShadow: focusedInput === 'email' ? '0 0 30px rgba(0, 212, 170, 0.25)' : 'none',
              }}>
                <span style={{ color: '#00d4aa', marginRight: '8px' }}>📧</span>
                <input
                  type="email"
                  value={form.email}
                  onChange={e => setForm({...form, email: e.target.value})}
                  onFocus={() => setFocusedInput('email')}
                  onBlur={() => setFocusedInput(null)}
                  required
                  style={{
                    background: 'transparent',
                    border: 'none',
                    color: 'white',
                    outline: 'none',
                    width: '100%',
                    padding: '14px 0',
                    fontSize: '15px',
                  }}
                  placeholder="admin@backersphere.com"
                  className="placeholder-gray-500"
                />
              </div>
            </div>

            {/* Password Field */}
            <div>
              <label style={{ color: '#a0aec0' }} className="block text-sm font-bold mb-2.5 uppercase tracking-wider">
                Password
              </label>
              <div style={{
                position: 'relative',
                display: 'flex',
                alignItems: 'center',
                background: 'linear-gradient(135deg, rgba(10, 13, 26, 0.96) 0%, rgba(10, 18, 35, 0.90) 100%)',
                border: `1.5px solid ${focusedInput === 'password' ? 'rgba(0, 212, 170, 0.5)' : 'rgba(0, 212, 170, 0.25)'}`,
                borderRadius: '14px',
                padding: '0 16px',
                transition: 'all 0.3s ease-out',
                boxShadow: focusedInput === 'password' ? '0 0 30px rgba(0, 212, 170, 0.25)' : 'none',
              }}>
                <span style={{ color: '#00d4aa', marginRight: '8px' }}>🔐</span>
                <input
                  type="password"
                  value={form.password}
                  onChange={e => setForm({...form, password: e.target.value})}
                  onFocus={() => setFocusedInput('password')}
                  onBlur={() => setFocusedInput(null)}
                  required
                  style={{
                    background: 'transparent',
                    border: 'none',
                    color: 'white',
                    outline: 'none',
                    width: '100%',
                    padding: '14px 0',
                    fontSize: '15px',
                  }}
                  placeholder="••••••••"
                  className="placeholder-gray-500"
                />
              </div>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={loading}
              style={{
                background: loading 
                  ? 'linear-gradient(135deg, rgba(0, 212, 170, 0.6) 0%, rgba(6, 182, 212, 0.5) 100%)' 
                  : 'linear-gradient(135deg, #00d4aa 0%, #06b6d4 100%)',
                color: '#000a0a',
                border: 'none',
                boxShadow: loading ? 'none' : '0 20px 50px rgba(0, 212, 170, 0.4)',
                width: '100%',
                padding: '16px',
                borderRadius: '12px',
                fontSize: '16px',
                fontWeight: 700,
                cursor: loading ? 'not-allowed' : 'pointer',
                transition: 'all 0.3s ease-out',
                marginTop: '28px',
              }}
              onMouseEnter={(e) => {
                if (!loading) {
                  e.currentTarget.style.transform = 'translateY(-3px)';
                  e.currentTarget.style.boxShadow = '0 30px 70px rgba(0, 212, 170, 0.5)';
                }
              }}
              onMouseLeave={(e) => {
                if (!loading) {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 20px 50px rgba(0, 212, 170, 0.4)';
                }
              }}
              className="uppercase tracking-wider"
            >
              {loading ? (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                  <span style={{ animation: 'pulse 1.5s ease-in-out infinite' }}>⏳</span>
                  Authenticating...
                </div>
              ) : (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                  <span>🔓</span>
                  Access Admin Panel
                </div>
              )}
            </button>

            {/* Security Notice */}
            <div style={{
              background: 'rgba(0, 212, 170, 0.12)',
              border: '1px solid rgba(0, 212, 170, 0.25)',
              borderRadius: '10px',
              padding: '12px 14px',
              marginTop: '20px',
            }}>
              <p style={{ color: '#cbd5e1', fontSize: '12px', lineHeight: '1.5' }}>
                🔒 This login is encrypted and monitored. Unauthorized access attempts are logged.
              </p>
            </div>
          </form>

          {/* Bottom Accent */}
          <div style={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            height: '2px',
            background: 'linear-gradient(90deg, transparent, rgba(0, 212, 170, 0.3), transparent)',
          }} />
        </div>

        {/* Footer Info */}
        <div style={{
          textAlign: 'center',
          marginTop: '32px',
          animation: 'slideUp 0.8s ease-out 0.3s both',
        }}>
          <p style={{ color: '#a0aec0', fontSize: '13px' }}>
            BackerSphere X • Admin Control Center
          </p>
          <p style={{ color: '#6b7280', fontSize: '12px', marginTop: '6px' }}>
            Powered by Gemini AI
          </p>
        </div>
      </div>
    </div>
  );
}
